// Decode the GitHub file payload and flatten dependencies into one item per package.
const raw = $input.first().json;
const b64 = raw.content || (raw.data && raw.data.content) || '';
const text = Buffer.from(b64, 'base64').toString('utf8');
let pkg;
try { pkg = JSON.parse(text); } catch (e) { throw new Error('package.json is not valid JSON: ' + e.message); }

const deps = { ...(pkg.dependencies || {}), ...(pkg.devDependencies || {}) };
const out = [];
for (const [name, range] of Object.entries(deps)) {
  // Skip local/git/workspace pins we can't check on the registry.
  if (/^(file:|link:|git|github:|workspace:|https?:)/i.test(range)) continue;
  out.push({
    json: {
      name,
      current_range: range,
      current_version: String(range).replace(/^[~^>=<\s]*/, '').split(' ')[0]
    }
  });
}
if (!out.length) return [{ json: { _empty: true } }];
return out;

const reg = $json;
const name = $('Parse Manifest').item.json.name;
const currentVersion = $('Parse Manifest').item.json.current_version;
const currentRange = $('Parse Manifest').item.json.current_range;
const distTags = reg['dist-tags'] || {};
const latest = distTags.latest || null;
const versions = reg.versions || {};
const time = reg.time || {};
const latestMeta = latest ? versions[latest] || {} : {};
const currentMeta = versions[currentVersion] || {};
const majorOf = v => v ? parseInt(String(v).split('.')[0], 10) : null;
const curMajor = majorOf(currentVersion), latestMajor = majorOf(latest);
const majorsBehind = (curMajor != null && latestMajor != null) ? Math.max(0, latestMajor - curMajor) : null;
let daysSinceLatest = null;
if (latest && time[latest]) daysSinceLatest = Math.round((Date.now() - new Date(time[latest]).getTime())/86400000);
return { json: { name, current_range: currentRange, current_version: currentVersion, latest_version: latest, majors_behind: majorsBehind, days_since_latest_publish: daysSinceLatest, current_version_deprecated: currentMeta.deprecated || null, latest_version_deprecated: latestMeta.deprecated || null, package_deprecated: reg.deprecated || null, engines: latestMeta.engines || null, homepage: reg.homepage || null, repository_url: (reg.repository && reg.repository.url) || null } };

